const now = new Date();
const saoPaulo = new Date(now.toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
saoPaulo.setDate(saoPaulo.getDate() - 1);
const pad = (n) => String(n).padStart(2, '0');
const yesterday = `${saoPaulo.getFullYear()}-${pad(saoPaulo.getMonth() + 1)}-${pad(saoPaulo.getDate())}`;
return [{ json: { date: yesterday } }];

const item = $input.first().json;
const date = $('Code: get yesterday (BRT)').first().json.date;
const accountId = $env.META_ROSE_AD_ACCOUNT_ID || '499901480052479';

if (item.error) {
  throw new Error(`Meta API error: ${item.error.message || JSON.stringify(item.error)}`);
}

const rawData = item.data || [];

if (rawData.length === 0) {
  return [{ json: { _no_data: true, date, accountId, message: `Sem dados Meta para ${date}` } }];
}

const CONV_TYPES = [
  'onsite_conversion.messaging_conversation_started_7d',
  'onsite_conversion.messaging_conversation_started_1d',
  'offsite_conversion.messaging_conversation_started_7d',
  'messaging_conversation_started'
];

const rows = rawData.map(row => {
  const actions = Array.isArray(row.actions) ? row.actions : [];
  const leads = actions.filter(a => a.action_type === 'lead')
    .reduce((s, a) => s + (parseInt(a.value) || 0), 0);
  const conversations = actions.filter(a => CONV_TYPES.includes(a.action_type))
    .reduce((s, a) => s + (parseInt(a.value) || 0), 0);
  return {
    date,
    client: 'rose',
    account_id: accountId,
    account_name: 'Rose Portal Advocacia',
    campaign_name: (row.campaign_name || '').slice(0, 500),
    adset_name: (row.adset_name || '').slice(0, 500),
    ad_name: (row.ad_name || '').slice(0, 500),
    objective: row.objective || null,
    impressions: parseInt(row.impressions) || 0,
    reach: parseInt(row.reach) || 0,
    clicks: parseInt(row.clicks) || 0,
    spend: parseFloat(row.spend) || 0,
    conversations,
    leads
  };
});

return [{ json: { _no_data: false, date, rows } }];

const res = $input.first().json;
const date = $('Code: get yesterday (BRT)').first().json.date;
const rows = $('Code: parse Meta data').first().json.rows || [];

if (res.statusCode && res.statusCode >= 400) {
  throw new Error(`Supabase upsert falhou ${res.statusCode}: ${JSON.stringify(res.body || res)}`);
}

// Agrega métricas por campanha
const byCampaign = {};
for (const row of rows) {
  const key = row.campaign_name;
  if (!byCampaign[key]) {
    byCampaign[key] = { campaign_name: key, spend: 0, leads: 0, conversations: 0 };
  }
  byCampaign[key].spend += row.spend || 0;
  byCampaign[key].leads += row.leads || 0;
  byCampaign[key].conversations += row.conversations || 0;
}

const campaigns = Object.values(byCampaign).sort((a, b) => b.spend - a.spend);
const totalSpend = campaigns.reduce((s, c) => s + c.spend, 0);
const totalLeads = campaigns.reduce((s, c) => s + c.leads + c.conversations, 0);

return [{ json: { date, campaigns, totalSpend, totalLeads } }];
